// Extract clips from WayinVideo results
const clips = $('4. WayinVideo — Get Clip Results').item.json.data?.clips || [];

if (clips.length === 0) {
  throw new Error('No clips returned from WayinVideo — check if the video URL is valid and publicly accessible.');
}

// Get form data
const webinarTitle = $('1. Form — Webinar URL + Course Details').item.json['Webinar / Course Title'];
const courseName = $('1. Form — Webinar URL + Course Details').item.json['Mini-Course Name'];
const targetAudience = $('1. Form — Webinar URL + Course Details').item.json['Target Audience'];
const brandName = $('1. Form — Webinar URL + Course Details').item.json['Brand / Sender Name'];
const emailTone = $('1. Form — Webinar URL + Course Details').item.json['Email Tone'];
const webinarUrl = $('1. Form — Webinar URL + Course Details').item.json['Webinar Recording URL'];

// Sort clips by score descending — best clips first
const sortedClips = clips.sort((a, b) => (b.score || 0) - (a.score || 0));

// Take top 5 — one per day
const topClips = sortedClips.slice(0, 5);

// Return one item per clip — each becomes one email day
return topClips.map((clip, index) => ({
  json: {
    dayNumber: index + 1,
    totalDays: topClips.length,
    clipTitle: clip.title || `Day ${index + 1} Lesson`,
    clipDescription: clip.desc || '',
    clipScore: clip.score || 0,
    clipTags: Array.isArray(clip.tags) ? clip.tags.join(', ') : '',
    beginMs: clip.begin_ms || 0,
    endMs: clip.end_ms || 0,
    timestampStart: `${Math.floor((clip.begin_ms || 0) / 60000)}:${String(Math.floor(((clip.begin_ms || 0) % 60000) / 1000)).padStart(2, '0')}`,
    timestampEnd: `${Math.floor((clip.end_ms || 0) / 60000)}:${String(Math.floor(((clip.end_ms || 0) % 60000) / 1000)).padStart(2, '00')}`,
    webinarTitle,
    courseName,
    targetAudience,
    brandName,
    emailTone,
    webinarUrl
  }
}));

// Parse AI email output into structured fields
const output = $input.first().json.output || '';

// Extract each section
const subjectMatch = output.match(/SUBJECT_LINE:\s*([\s\S]*?)(?=\nPREVIEW_TEXT:|$)/);
const previewMatch = output.match(/PREVIEW_TEXT:\s*([\s\S]*?)(?=\nEMAIL_BODY:|$)/);
const bodyMatch = output.match(/EMAIL_BODY:\s*([\s\S]*?)(?=\nKEY_TAKEAWAY:|$)/);
const takeawayMatch = output.match(/KEY_TAKEAWAY:\s*([\s\S]*?)(?=\nCTA_TEXT:|$)/);
const ctaTextMatch = output.match(/CTA_TEXT:\s*([\s\S]*?)(?=\nCTA_URL_PLACEHOLDER:|$)/);
const ctaUrlMatch = output.match(/CTA_URL_PLACEHOLDER:\s*([\s\S]*)$/);

const subjectLine = subjectMatch ? subjectMatch[1].trim() : '';
const previewText = previewMatch ? previewMatch[1].trim() : '';
const emailBody = bodyMatch ? bodyMatch[1].trim() : '';
const keyTakeaway = takeawayMatch ? takeawayMatch[1].trim() : '';
const ctaText = ctaTextMatch ? ctaTextMatch[1].trim() : '';
const ctaUrl = ctaUrlMatch ? ctaUrlMatch[1].trim() : 'YOUR_LINK_HERE';

if (!subjectLine || !emailBody) {
  throw new Error('Could not parse email from AI output. Check the prompt output format.');
}

// Get clip data from step 7
const clipData = $('7. Code — Extract Clips + Assign Days').item.json;

return [{
  json: {
    dayNumber: clipData.dayNumber,
    subjectLine,
    previewText,
    emailBody,
    keyTakeaway,
    ctaText,
    ctaUrl,
    wordCount: emailBody.split(/\s+/).length,
    clipTitle: clipData.clipTitle,
    clipScore: clipData.clipScore,
    timestamp: `${clipData.timestampStart} — ${clipData.timestampEnd}`,
    webinarTitle: clipData.webinarTitle,
    courseName: clipData.courseName,
    targetAudience: clipData.targetAudience,
    brandName: clipData.brandName,
    webinarUrl: clipData.webinarUrl
  }
}];
